<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Bouncing Ball Physics</title>
<style>
  * { box-sizing: border-box; margin: 0; padding: 0; }
  body {
    min-height: 100vh;
    display: flex;
    flex-direction: column;
    align-items: center;
    justify-content: center;
    background: #0d0d12;
    color: #e8e8f0;
    font-family: system-ui, -apple-system, sans-serif;
    gap: 16px;
    padding: 20px;
  }
  h1 {
    font-size: 1.25rem;
    font-weight: 600;
    letter-spacing: 0.04em;
    color: #a0a0b8;
  }
  #sim {
    display: block;
    width: 480px;
    height: 480px;
    max-width: 90vw;
    max-height: 70vh;
    background: #16161f;
    border: 2px solid #2a2a3a;
    border-radius: 8px;
    cursor: crosshair;
    box-shadow: 0 8px 32px rgba(0,0,0,0.5), inset 0 0 60px rgba(0,0,0,0.3);
  }
  .controls {
    display: flex;
    gap: 10px;
    flex-wrap: wrap;
    justify-content: center;
  }
  button {
    appearance: none;
    border: 1px solid #3a3a50;
    background: #1e1e2c;
    color: #e0e0f0;
    padding: 10px 22px;
    border-radius: 6px;
    font-size: 0.95rem;
    font-weight: 500;
    cursor: pointer;
    transition: background 0.15s, border-color 0.15s, transform 0.1s;
  }
  button:hover {
    background: #2a2a40;
    border-color: #5a5a80;
  }
  button:active {
    transform: scale(0.96);
  }
  button.playing {
    background: #2a3a2a;
    border-color: #4a8a4a;
    color: #a0e0a0;
  }
</style>
</head>
<body>
  <h1>Bouncing Ball Playground</h1>
  <canvas id="sim" width="480" height="480"></canvas>
  <div class="controls">
    <button id="drop">Drop</button>
    <button id="play">Play</button>
    <button id="clear">Clear</button>
  </div>
<script>
(function () {
  const canvas = document.getElementById('sim');
  const ctx = canvas.getContext('2d');
  const W = canvas.width;
  const H = canvas.height;

  const GRAVITY = 0.35;
  const RESTITUTION = 0.82;
  const FRICTION = 0.995;

  /** @type {{x:number,y:number,vx:number,vy:number,r:number,color:string}[]} */
  let balls = [];
  let playing = false;
  let animId = null;

  const COLORS = [
    '#ff6b6b', '#feca57', '#48dbfb', '#1dd1a1',
    '#5f27cd', '#ff9ff3', '#54a0ff', '#00d2d3',
    '#ff9f43', '#ee5a24', '#c8d6e5', '#10ac84'
  ];

  function randomColor() {
    return COLORS[Math.floor(Math.random() * COLORS.length)];
  }

  function addBall(x, y, vx, vy, r) {
    if (vx === undefined) vx = 0;
    if (vy === undefined) vy = 0;
    if (r === undefined || r === null) r = 12 + Math.random() * 18;
    // Clamp so ball starts fully inside
    x = Math.max(r, Math.min(W - r, x));
    y = Math.max(r, Math.min(H - r, y));
    balls.push({ x, y, vx, vy, r, color: randomColor() });
    draw();
  }

  function clearBalls() {
    balls = [];
    draw();
  }

  function step(dt) {
    if (dt === undefined) dt = 1;
    for (let i = 0; i < balls.length; i++) {
      const b = balls[i];
      // Gravity
      b.vy += GRAVITY * dt;
      // Integrate
      b.x += b.vx * dt;
      b.y += b.vy * dt;
      // Light air friction
      b.vx *= Math.pow(FRICTION, dt);
      b.vy *= Math.pow(FRICTION, dt);

      // Bounce left
      if (b.x - b.r < 0) {
        b.x = b.r;
        b.vx = Math.abs(b.vx) * RESTITUTION;
      }
      // Bounce right
      if (b.x + b.r > W) {
        b.x = W - b.r;
        b.vx = -Math.abs(b.vx) * RESTITUTION;
      }
      // Bounce top
      if (b.y - b.r < 0) {
        b.y = b.r;
        b.vy = Math.abs(b.vy) * RESTITUTION;
      }
      // Bounce bottom
      if (b.y + b.r > H) {
        b.y = H - b.r;
        b.vy = -Math.abs(b.vy) * RESTITUTION;
      }
    }
    draw();
  }

  function draw() {
    ctx.fillStyle = '#16161f';
    ctx.fillRect(0, 0, W, H);

    // Subtle grid
    ctx.strokeStyle = 'rgba(255,255,255,0.03)';
    ctx.lineWidth = 1;
    for (let g = 40; g < W; g += 40) {
      ctx.beginPath(); ctx.moveTo(g, 0); ctx.lineTo(g, H); ctx.stroke();
    }
    for (let g = 40; g < H; g += 40) {
      ctx.beginPath(); ctx.moveTo(0, g); ctx.lineTo(W, g); ctx.stroke();
    }

    for (let i = 0; i < balls.length; i++) {
      const b = balls[i];
      // Shadow
      ctx.beginPath();
      ctx.arc(b.x + 2, b.y + 3, b.r, 0, Math.PI * 2);
      ctx.fillStyle = 'rgba(0,0,0,0.35)';
      ctx.fill();
      // Ball
      const grad = ctx.createRadialGradient(
        b.x - b.r * 0.35, b.y - b.r * 0.35, b.r * 0.1,
        b.x, b.y, b.r
      );
      grad.addColorStop(0, lighten(b.color, 0.45));
      grad.addColorStop(0.55, b.color);
      grad.addColorStop(1, darken(b.color, 0.35));
      ctx.beginPath();
      ctx.arc(b.x, b.y, b.r, 0, Math.PI * 2);
      ctx.fillStyle = grad;
      ctx.fill();
      // Highlight
      ctx.beginPath();
      ctx.arc(b.x - b.r * 0.3, b.y - b.r * 0.3, b.r * 0.22, 0, Math.PI * 2);
      ctx.fillStyle = 'rgba(255,255,255,0.35)';
      ctx.fill();
    }
  }

  function lighten(hex, amt) {
    const n = parseInt(hex.slice(1), 16);
    let r = (n >> 16) & 255, g = (n >> 8) & 255, b = n & 255;
    r = Math.min(255, Math.round(r + (255 - r) * amt));
    g = Math.min(255, Math.round(g + (255 - g) * amt));
    b = Math.min(255, Math.round(b + (255 - b) * amt));
    return 'rgb(' + r + ',' + g + ',' + b + ')';
  }

  function darken(hex, amt) {
    const n = parseInt(hex.slice(1), 16);
    let r = (n >> 16) & 255, g = (n >> 8) & 255, b = n & 255;
    r = Math.max(0, Math.round(r * (1 - amt)));
    g = Math.max(0, Math.round(g * (1 - amt)));
    b = Math.max(0, Math.round(b * (1 - amt)));
    return 'rgb(' + r + ',' + g + ',' + b + ')';
  }

  function loop() {
    if (!playing) return;
    step(1);
    animId = requestAnimationFrame(loop);
  }

  function setPlaying(on) {
    playing = on;
    const btn = document.getElementById('play');
    if (playing) {
      btn.textContent = 'Pause';
      btn.classList.add('playing');
      if (!animId) animId = requestAnimationFrame(loop);
    } else {
      btn.textContent = 'Play';
      btn.classList.remove('playing');
      if (animId) { cancelAnimationFrame(animId); animId = null; }
    }
  }

  // UI
  document.getElementById('drop').addEventListener('click', function () {
    const r = 12 + Math.random() * 18;
    const x = r + Math.random() * (W - 2 * r);
    const y = r + Math.random() * 40;
    const vx = (Math.random() - 0.5) * 8;
    addBall(x, y, vx, 0, r);
  });

  document.getElementById('play').addEventListener('click', function () {
    setPlaying(!playing);
  });

  document.getElementById('clear').addEventListener('click', function () {
    clearBalls();
  });

  canvas.addEventListener('click', function (e) {
    const rect = canvas.getBoundingClientRect();
    const scaleX = canvas.width / rect.width;
    const scaleY = canvas.height / rect.height;
    const x = (e.clientX - rect.left) * scaleX;
    const y = (e.clientY - rect.top) * scaleY;
    const r = 12 + Math.random() * 18;
    const vx = (Math.random() - 0.5) * 6;
    const vy = (Math.random() - 0.5) * 4;
    addBall(x, y, vx, vy, r);
  });

  // Programmatic API
  window.sim = {
    get w() { return W; },
    get h() { return H; },
    balls: function () {
      return balls.map(function (b) {
        return { x: b.x, y: b.y, vx: b.vx, vy: b.vy, r: b.r };
      });
    },
    addBall: function (x, y, vx, vy, r) {
      addBall(x, y, vx, vy, r);
    },
    clear: function () {
      clearBalls();
    },
    step: function (dt) {
      step(dt);
    }
  };

  draw();
})();
</script>
</body>
</html>
